import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.b3aQeZRM.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),r={name:"architecture.md"};function i(l,e,n,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Relay is a protocol adapter that sits between agent clients and local LLM servers.</p><h2 id="two-operating-modes" tabindex="-1">Two Operating Modes <a class="header-anchor" href="#two-operating-modes" aria-label="Permalink to &quot;Two Operating Modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td><strong>Gateway</strong></td><td>Manages local llama.cpp models. Auto lifecycle: start, stop, switch. Forwards unknown models to cloud fallback if configured.</td></tr><tr><td><strong>Cloud</strong></td><td>Proxies to external APIs (OpenAI, Anthropic, DeepSeek, Groq). No local GPU needed. Per-model base URL and auth.</td></tr></tbody></table><h2 id="request-flow" tabindex="-1">Request Flow <a class="header-anchor" href="#request-flow" aria-label="Permalink to &quot;Request Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client (OpenAI/Anthropic)</span></span>
<span class="line"><span>  → endpoint parser + auth + field policy</span></span>
<span class="line"><span>  → canonical request (provider-agnostic intermediate form)</span></span>
<span class="line"><span>  → upstream OpenAI-compatible chat request</span></span>
<span class="line"><span>  → canonical response / stream events</span></span>
<span class="line"><span>  → client protocol response (shape-matched to inbound protocol)</span></span></code></pre></div><h2 id="canonical-pipeline" tabindex="-1">Canonical Pipeline <a class="header-anchor" href="#canonical-pipeline" aria-label="Permalink to &quot;Canonical Pipeline&quot;">​</a></h2><p>Relay normalizes everything through a provider-neutral canonical form:</p><ul><li>Request model: <code>src/internal/canonical.ts</code></li><li>Protocol converters: <code>src/internal/openai-chat.ts</code>, <code>src/internal/openai-responses.ts</code>, <code>src/internal/anthropic-messages.ts</code></li><li>Response model: <code>src/internal/response.ts</code></li><li>Shared sampling logic: <code>src/internal/sampling.ts</code></li></ul><h2 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h2><ul><li>OpenAI chat streams emit repaired <code>[DONE]</code> terminators</li><li>Responses streams emit the full SSE event lifecycle (output_item, content_part, text_delta, function_call_arguments, completed)</li><li>Anthropic streams emit message_start, content_block, message_delta, message_stop events</li><li>Missing terminators are repaired; duplicates are collapsed</li></ul><h2 id="auto-model-lifecycle" tabindex="-1">Auto Model Lifecycle <a class="header-anchor" href="#auto-model-lifecycle" aria-label="Permalink to &quot;Auto Model Lifecycle&quot;">​</a></h2><p>When enabled, Relay manages model processes:</p><ul><li>Spawns model servers on dedicated ports (8081+)</li><li>Routes requests to the correct port via <code>getUpstreamUrl()</code></li><li>Kills old models when switching (eager switching)</li><li>Clears KV cache on session change</li><li>Cleans orphan processes from previous instances on startup</li></ul><h2 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h2><p>When <code>RELAY_OBSERVABILITY_ENABLED=true</code>:</p><ul><li><code>GET /</code> — HTML dark-theme dashboard with model table, queue cards, lifecycle state</li><li><code>GET /health</code> — JSON liveness check</li><li><code>GET /relay/status</code> — full lifecycle + queue status</li><li><code>GET /relay/metrics</code> — request counts, latencies, error rates</li><li><code>GET /relay/jobs</code> — job queue state</li><li><code>GET /relay/lifecycle</code> — per-model process details</li><li><code>GET /relay/stats</code> — request history</li><li><code>GET /relay/capabilities</code> — capability matrix</li></ul><p>All sensitive values (API keys, auth headers) are redacted in logs and observability output.</p><h2 id="response-store" tabindex="-1">Response Store <a class="header-anchor" href="#response-store" aria-label="Permalink to &quot;Response Store&quot;">​</a></h2><p>The <code>/v1/responses</code> endpoint stores completed responses in an in-memory store with:</p><ul><li>Full chat message history for <code>previous_response_id</code> conversation continuation</li><li>TTL-based expiry (<code>COMPLETION_TTL_SECONDS</code>)</li><li>Memory-bound eviction (<code>maxStoreEntries</code>, <code>maxStoreBytes</code>)</li></ul><h2 id="key-modules" tabindex="-1">Key Modules <a class="header-anchor" href="#key-modules" aria-label="Permalink to &quot;Key Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Purpose</th></tr></thead><tbody><tr><td><code>src/server.ts</code></td><td>HTTP server, routing, auth, rate limiting, mutex, cloud fallback</td></tr><tr><td><code>src/config.ts</code></td><td>Environment variable loading and validation</td></tr><tr><td><code>src/auth.ts</code></td><td>API key validation, per-key rate limiting (<code>KeyRateLimiter</code>)</td></tr><tr><td><code>src/lifecycle.ts</code></td><td>Model process management (start, stop, switch, probe, idle shutdown)</td></tr><tr><td><code>src/openai/responses.ts</code></td><td><code>/v1/responses</code> handler, streaming SSE lifecycle, <code>ResponseStore</code></td></tr><tr><td><code>src/openai/chat.ts</code></td><td><code>/v1/chat/completions</code> handler</td></tr><tr><td><code>src/internal/openai-responses.ts</code></td><td>Responses → canonical conversion, tool normalization</td></tr><tr><td><code>src/upstream/llama.ts</code></td><td>Upstream HTTP client with auth header injection</td></tr><tr><td><code>src/normalize/</code></td><td>Message, tool, and stream normalization</td></tr></tbody></table>`,23)])])}const m=t(r,[["render",i]]);export{u as __pageData,m as default};
